import { Marker } from "react-leaflet";
import L from "leaflet";

// IMPORTANT: make sure this file exists in public folder
const planeIcon = new L.Icon({
  iconUrl: "/plane.png",
  iconSize: [40, 40],
  iconAnchor: [20, 20],
});

export default function PlaneMarker({ position }) {
  return <Marker position={position} icon={planeIcon} />;
}
